"""
MKT Original Commentary — Mark chapters 7–8
Run: python3 scripts/zc-original-mark-7-8.py

Source data used:
- data/interlinear/mark.json
- data/translation/draft/mediating/mark.json
- data/commentary/mkt-original/mark.json (existing entries skipped by merge_comm)

Key decisions in this range:
- 7:3 pugmē: textual crux; UBS5 reads pugmē ("with a fist" / vigorously); MKT follows
  the majority reading without harmonizing to Matthew
- 7:11 korban: Aramaic loanword preserved; explained in commentary as temple-dedication
  loophole that nullifies parental-support duty
- 7:19 katharizōn panta ta brōmata: Mark's editorial parenthetical declaring all foods
  clean — absent from Matthew's parallel; treated as Markan theological interpretation
- 7:32 mogilalos: the Isaiah 35:6 LXX word; signals messianic sign fulfillment
- 8:8 spyridas vs kophinus (6:43): basket-type change supports Gentile-territory reading
- 8:24: two-stage healing treated as structural mirror of disciples' gradual understanding
- 8:31 dei: divine necessity — passion is not accidental but ordained
- 8:38 epaischynthē: honor-shame cultural context; public dissociation from Christ
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK = {
  "7": {
    "1": '<p><strong>hoi Pharisaioi kai tines tōn grammateōn elthontes apo Hierosolymōn</strong> — Pharisees and some of the scribes having come from Jerusalem — the delegation from the capital marks an escalation: this is not local scribal scrutiny (as in 2:6; 3:22) but an official investigation mounted from Jerusalem. The combination of Pharisees (lay pietists concerned with halakhic observance) and scribes (legal scholars and Torah-interpreters) constitutes a joint inquiry into the movement\'s practices.</p>',
    "2": '<p><strong>koinais chersin, tout\' estin aniptois</strong> — with common hands, that is, unwashed — <em>koinos</em> (common, defiled, ritually impure) is the LXX and NT technical term for the state of ritual impurity; the parenthetical "that is, unwashed" (<em>tout\' estin aniptois</em>) is Mark\'s aside explaining Jewish purity practice to Gentile readers unfamiliar with the custom. The accusation is halakhic non-compliance, not hygiene.</p>',
    "3": '<p><strong>pugmē</strong> — the term is lexically debated: (1) "with a fist" = scrubbing vigorously with a cupped hand; (2) "up to the wrist/elbow" (a few MSS support a distance-measure reading). UBS5/NA28 reads <em>pugmē</em>. Whatever the specific gesture, the parenthetical vv.3–4 is a Markan explanatory aside for non-Jewish readers, establishing the traditional practice before Jesus\'s ruling on it.</p>',
    "4": '<p><strong>kai apo agoras ean mē baptisōntai ouk esthiousin</strong> — and from the marketplace unless they immerse they do not eat — <em>baptizō</em> (to dip, immerse) here refers to ritual immersion after contact with potentially impure persons in the marketplace. The additional listed practices — immersing cups, pitchers, and copper vessels, and <em>klinōn</em> (dining couches) in some manuscripts — show how pervasively ritual purity governed daily domestic life. Defilement could pass through objects, not only persons.</p>',
    "5": '<p><strong>dia ti ou peripatousin hoi mathētai sou kata tēn paradosin tōn presbyterōn</strong> — why do your disciples not walk according to the tradition of the elders — <em>paradosis</em> (tradition, what is handed over/passed down — from <em>paradidonai</em>) is the disputed term. The scribes frame the issue as violation of ancestral custom rather than Torah itself. Jesus\'s response will reverse the frame: it is the tradition that violates Torah.</p>',
    "6": '<p><strong>ho de eipen autois, Kalōs eprophēteusen Hsaias peri hymōn tōn hypokritōn</strong> — and he said to them: rightly Isaiah prophesied about you hypocrites — <em>hypokritēs</em> (actor wearing a mask, stage-performer) is the word for theatrical performance in Greek; those who speak lines not their own character. The citation follows: Isaiah 29:13 LXX. <strong>houtos ho laos tois cheilesin me tima, hē de kardia autōn porrō apechei ap\' emou</strong> — this people honors me with lips but their heart is far from me — the lips/heart contrast is the prophetic anatomy of empty religion: external speech without inward reality.</p>',
    "7": '<p><strong>matēn de sebontai me, didaskontes didaskalias entalmata anthrōpōn</strong> — they worship me in vain, teaching as doctrines human commandments — <em>matēn</em> (in vain, without purpose, to no effect — the worship achieves nothing). The LXX version of Isaiah 29:13 is actually stronger at this point than the Hebrew MT, using <em>entalmata anthrōpōn</em> (human commandments/injunctions) to characterize the teaching. The human origin of the tradition (<em>anthrōpōn</em>) is contrasted throughout with the divine origin of the law (<em>entolē tou theou</em> in vv.8–9).</p>',
    "8": '<p><strong>aphentes tēn entolēn tou theou krateite tēn paradosin tōn anthrōpōn</strong> — letting go of the commandment of God you hold the tradition of men — <em>entolē</em> (commandment, from <em>entellomai</em> = to give authoritative command) vs. <em>paradosis</em> (tradition, secondary transmission). The opposition is structural: divine commandment released, human tradition grasped. The priority is inverted: what God directly commanded is treated as secondary to what the elders subsequently taught.</p>',
    "9": '<p><strong>kalōs atheteite tēn entolēn tou theou hina tēn paradosin hymōn stēsēte</strong> — rightly you set aside the commandment of God in order to establish your tradition — <em>kalōs</em> is bitterly ironic: "nicely/skillfully you do it." <em>atheteō</em> (to set aside, declare void — from <em>a-</em> + <em>tithēmi</em> = to un-place, unmake the position of) is the legal term for rendering a ruling or obligation invalid. The purpose clause <em>hina ... stēsēte</em> (in order that you might establish) exposes the implicit logic: tradition is upheld at Torah\'s expense.</p>',
    "10": '<p><strong>Mōysēs gar eipen, Tima ton patera sou kai tēn mētera sou</strong> — for Moses said: Honor your father and your mother — the Moses-said formula grounds the commandment in Sinai authority (Exod 20:12; Deut 5:16). The second citation — "the one who curses father or mother, let him die" (Exod 21:17; Lev 20:9) — is the capital-penalty provision that underlines how seriously Torah treats parental honor. Jesus establishes the Torah\'s own severity before exposing the tradition\'s circumvention of it.</p>',
    "11": '<p><strong>korban, ho estin dōron</strong> — Korban, which is a gift — <em>korban</em> is the Aramaic loanword for a gift dedicated to the temple treasury (Hebrew <em>qorban</em>, from <em>qarab</em> = to draw near, to offer). Once resources were declared korban — dedicated to God — they could not legally be redirected, even to support parents in material need. The tradition thus created a halakhically valid mechanism by which a son could exempt himself from financial parental support (<em>ou mē ōphelēthēs ex emou</em> = you will not be benefited from me) by invoking a temple-dedication vow.</p>',
    "12": '<p><strong>ouketi aphiete auton ouden poiēsai tō patri ē tē mētri</strong> — you no longer permit him to do anything for his father or mother — the legal consequence: the korban-declaration extinguishes all subsequent obligation to parents. The tradition has not merely supplemented Torah; it has generated a loophole that makes Torah compliance <em>impossible</em> once the vow is made. Jesus\'s case study concretizes the abstract charge of v.8–9 with a specific mechanism.</p>',
    "13": '<p><strong>akyrountes ton logon tou theou tē paradosei hymōn hē paredōkate</strong> — nullifying the word of God by your tradition which you have handed on — <em>akyrouō</em> (to make without authority, to annul — from <em>a-</em> + <em>kyrios</em> = making the Lord\'s ruling invalid) is the antonym of <em>kyroō</em> (to confirm, validate). The tradition (<em>paradosis</em>) has accumulated institutional authority sufficient to effectively override Torah. "And many such things like this you do" — the korban case is one instance of a systemic pattern, not an isolated exception.</p>',
    "14": '<p><strong>kai proskalesamenos palin ton ochlon elegen autois</strong> — and calling the crowd to himself again he said — Jesus widens the audience from the Pharisees/scribes (vv.1–13) to the crowd. The teaching that follows is addressed publicly. <strong>Akouete mou pantes kai suniete</strong> — hear me all and understand — the double imperative with <em>pantes</em> (all) marks this as a universal public declaration, not a private rulings addressed only to the questioning party.</p>',
    "15": '<p><strong>ouden estin exōthen tou anthrōpou eisporeuomenon eis auton ho dynatai koinōsai auton</strong> — nothing outside the person entering into him is able to defile him — <em>koinoō</em> (to make common, to render ritually impure) is the verb throughout the pericope. The principle reverses the Levitical purity paradigm: defilement moves outward from the person, not inward from outside. The implication for the food-law controversy is radical: what is eaten (external to the person) cannot be the source of defilement.</p>',
    "16": '<p>Many manuscripts include <em>ei tis echei ōta akouein akouetō</em> — if anyone has ears to hear, let him hear — as v.16, an interpolation from 4:9,23. UBS5/NA28 brackets or omits it. If original, it would signal this teaching as parabolic in character, requiring inner-ear understanding rather than surface-level hearing — consistent with the private explanation that follows in vv.17–23.</p>',
    "17": '<p><strong>kai hote eisēlthen eis oikon apo tou ochlou, epērōtōn auton hoi mathētai autou tēn parabolēn</strong> — and when he entered a house away from the crowd his disciples asked him about the parable — the house/crowd spatial division recurs (cf. 4:10; 7:24; 9:28; 10:10): private explanation follows public proclamation. <em>parabolē</em> is used broadly for any dark or enigmatic saying, not only narrative parables. <strong>Outōs kai hymeis asyntetoi este</strong> — are you also without understanding — <em>asynetos</em> (without comprehension — from <em>a-</em> + <em>syniēmi</em> = failing to put it together) is the word for those who cannot assemble the evidence into understanding; cf. 8:17, 21.</p>',
    "18": '<p><strong>ou noeite hoti pan to exōthen eisporeuomenon eis ton anthrōpon ou dynatai auton koinōsai</strong> — do you not understand that nothing entering the person from outside is able to defile him — <em>noeō</em> (to perceive with the mind, to grasp intellectually — from <em>nous</em>) is paired with the negative <em>ou</em>: the disciples\' cognitive failure is named. The re-statement of v.15 is slightly expanded with the digestive explanation that follows in v.19: what enters goes into the stomach, not the heart (<em>kardia</em>), and is expelled — the physical process cannot touch the moral centre.</p>',
    "19": '<p><strong>hoti ouk eisporeuetai autou eis tēn kardian all\' eis tēn koilian, kai eis ton aphedrōna ekporeuetai, katharizōn panta ta brōmata</strong> — because it does not enter his heart but his stomach and goes out into the latrine, cleansing all foods — the parenthetical <em>katharizōn panta ta brōmata</em> (cleansing/declaring clean all foods) is Mark\'s editorial aside identifying the ruling implication of Jesus\'s teaching. This phrase is absent from Matthew\'s parallel (15:17). It is the most significant halakhic ruling in the Gospel traditions, effectively overturning the Levitical dietary laws (Lev 11), and anticipates the vision in Acts 10:15 and Paul\'s teaching in Romans 14. The subject of <em>katharizōn</em> is disputed: the grammatically nearest antecedent is Jesus, making this a Markan declaration that Jesus declared all foods clean.</p>',
    "20": '<p><strong>to de ek tou anthrōpou ekporeuomenon, ekeino koinoi ton anthrōpon</strong> — but what comes out of the person, that defiles the person — the inverted principle is stated explicitly: defilement has a single source, the human interior. The list that follows (vv.21–22) catalogs what the interior produces. The contrast with Levitical purity (which assigned defilement to external objects, foods, bodily discharges) is complete: for Jesus, the heart is the source, not the skin or stomach.</p>',
    "21": '<p><strong>esōthen gar ek tēs kardias tōn anthrōpōn hoi dialogismoi hoi kakoi ekporeuontai</strong> — for from within, from the heart of persons, the evil reasonings come out — <em>dialogismos</em> (reasoning, deliberation — from <em>dialogizomai</em> = to reason through; in NT consistently the internal deliberation that produces moral conclusions) is the first item: cognitive evil, the mind\'s disposition. The following list of 6 plural nouns (fornications, thefts, murders, adulteries, covetings, wickednesses) and 6 singular nouns (deceit, sensuality, evil eye, slander, arrogance, folly) is a catalog of inward moral corruption, not ritual violation.</p>',
    "22": '<p><strong>aselgeia</strong> — sensuality, licentiousness (the absence of moral restraint); <strong>ophthalmos ponēros</strong> — evil eye — in Semitic idiom, the evil eye is envy and miserliness (Matt 6:23; Prov 23:6 LXX), not an occult gaze; <strong>blasphēmia</strong> — slander, defamation (of persons as well as God); <strong>hyperēphania</strong> — arrogance, haughtiness (from <em>hyper</em> + <em>phainomai</em> = appearing above others — the pride of social superiority); <strong>aphrosynē</strong> — folly, senselessness (the moral failure of not acknowledging God). The list ends with the foolishness that Proverbs names as the foundation of all moral failure.</p>',
    "23": '<p><strong>panta tauta ta ponēra esōthen ekporeuetai kai koinoi ton anthrōpon</strong> — all these evil things come out from within and defile the person — the concluding summary applies <em>koinoō</em> (defile) to the list. The pericope\'s argument is complete: the tradition\'s application of <em>koinōsis</em> to unwashed hands is misapplied; the real defilement comes from the moral interior, not from physical contact with food or persons.</p>',
    "24": '<p><strong>kai ekeithen anastas apēlthen eis ta horia Tyrou</strong> — and rising from there he departed into the regions of Tyre — Tyre is on the Phoenician coast approximately 35 miles northwest of Capernaum — Gentile territory entirely outside Jewish Galilee. <strong>kai eiselthōn eis oikian oudena ēthelen gnōnai, kai ouk ēdynasthē lathein</strong> — and entering a house he wanted no one to know, and he was unable to escape notice — the Messianic Secret maintained: private residence, no-announcement intention. But his reputation precedes him even into Gentile regions; the attempt at concealment fails immediately.</p>',
    "25": '<p><strong>all\' eutheōs akousasa gynē peri autou, hēs eichen to thygatrion autēs pneuma akatharton</strong> — but immediately a woman whose little daughter had an unclean spirit, having heard about him — <em>eutheōs</em> again; the woman\'s approach is immediate upon hearing. <em>thygatrion</em> (little daughter — diminutive of <em>thygatēr</em>) is the affectionate parental form, as with Jairus\'s daughter (5:23). <em>prosepesen pros tous podas autou</em> (fell at his feet) — the posture of extreme supplication, as with Jairus (5:22) and the Gerasene man (5:33). The same gesture crosses cultural boundaries.</p>',
    "26": '<p><strong>hē de gynē ēn Hellēnis, Syrophoinikissa tō genei</strong> — the woman was Greek/Gentile, Syrophoenician by race — <em>Hellēnis</em> (Hellenist — Greek-speaking, Gentile by culture) identifies her cultural orientation; <em>Syrophoinikissa tō genei</em> (Syrophoenician by race/descent) specifies ethnic origin — Phoenician Syria as distinct from Libyan Phoenicia. She is doubly marked as non-Jewish, and her request is that Jesus cast the demon out of her daughter. The initial response Jesus gives (v.27) will test the mission-boundary question directly.</p>',
    "27": '<p><strong>aphes prōton chortasthēnai ta tekna</strong> — let the children first be satisfied/filled — <em>prōton</em> (first) is the key word: it acknowledges mission-priority (Israel before Gentiles) without making that priority absolute or eternal. <em>chortazō</em> (to be filled, satisfied — used for feeding animals and, in the Beatitude, those who hunger) matches the feeding-miracle language. <strong>ou gar kalon estin labein ton arton tōn teknōn kai tois kynarois balein</strong> — for it is not good to take the children\'s bread and throw it to the dogs — <em>kynarion</em> (little dog, household dog — diminutive) is a softened form; <em>kyōn</em> (the street-dog insult) is not used. The children-dogs metaphor maps covenant Israel (<em>tekna</em>) vs. Gentiles (<em>kynaria</em>) with the ordering acknowledged but not the exclusion made permanent.</p>',
    "28": '<p><strong>kyrie, kai ta kynarion hypokato tēs trapezēs esthiousin apo tōn psichōn tōn paidōn</strong> — Lord, even the little dogs under the table eat from the children\'s crumbs — <em>kyrie</em> (Lord/Master) is her address, acknowledging his authority. The woman accepts the image and works within its logic: she does not claim the children\'s portion but only the <em>psichōn</em> (crumbs, fragments — the scraps that fall from the table). The reply is neither an argument against the ordering nor a rejection of it; it works within the metaphor to find space for Gentile participation at its margins. The theological brilliance is that she claims the overflow of the children\'s blessing, not the blessing itself.</p>',
    "29": '<p><strong>dia touton ton logon hypage</strong> — because of this word/saying, go — the woman\'s <em>logos</em> (word, response, saying) is what Jesus names as the reason for the healing. In Matthew\'s parallel (15:28) it is her faith (<em>pistis</em>) that is named; in Mark it is the word she spoke. The healing is pronounced before any physical contact or return home: Jesus declares the demon departed (<em>exelēlythen to daimonion ek tēs thygatros sou</em> = the demon has gone out from your daughter) at a distance and in the past tense. The departure has already occurred.</p>',
    "30": '<p><strong>kai apelthousa eis ton oikon autēs heuren to paidion beblēmenon epi tēn klinēn kai to daimonion exelēlythos</strong> — going to her house she found the child lying on the bed and the demon gone — both participles are perfects: <em>beblēmenon</em> (having been cast/laid — perfect passive of <em>ballō</em>) and <em>exelēlythos</em> (having gone out — perfect active of <em>exerchomai</em>). The perfect tenses indicate completed states at the time of discovery — the healing had already occurred, precisely when Jesus\'s word was spoken. The physical verification confirms the remotely-spoken pronouncement.</p>',
    "31": '<p><strong>kai palin exelthōn ek tōn horiōn Tyrou ēlthen dia Sidōnos eis tēn thalassan tēs Galilaias ana meson tōn horiōn Dekapoleōs</strong> — and leaving the region of Tyre he came through Sidon to the Sea of Galilee through the middle of the region of the Decapolis — the route is geographically unusual: Sidon is north of Tyre, making the path north-then-south before arriving at Galilee via the eastern Decapolis. Some scholars have proposed a geographical error; others read it as an extended Gentile mission circuit. The Decapolis (<em>ana meson</em> = through the middle) is where the Gerasene had been sent as missionary (5:20): Jesus moves through the territory that man had evangelized.</p>',
    "32": '<p><strong>kai pherosin autō kōphon kai mogillalon kai parakalosin auton hina epithē autō tēn cheira</strong> — and they brought to him a deaf man speaking with difficulty and they begged him to lay his hand on him — <em>kōphos</em> (deaf/mute — Greek uses one word for both) describes the primary impairment; <em>mogilalos</em> (speaking with difficulty, barely able to speak — from <em>mogis</em> = scarcely + <em>laleō</em> = speak) is a rare word that appears in the Greek OT (LXX) at Isaiah 35:6: "the tongue of the mute (<em>mogilalōn</em>) will shout for joy." Mark\'s use of the Isaiah-vocabulary signals that the messianic healing-sign of the Isaianic new exodus is being enacted.</p>',
    "33": '<p><strong>kai apolabomenos auton apo tou ochlou kat\' idian</strong> — taking him apart from the crowd privately — the withdrawal from public space for private healing recurs (5:40; 8:23): the healing is not a public performance. The physical method: (1) <em>ebalen tous daktylous autou eis ta ōta autou</em> (put his fingers into the man\'s ears); (2) <em>ptysas hēpsato tēs glōssēs autou</em> (having spat he touched his tongue) — spittle used as a healing medium, consistent with 8:23. The physical contact with the affected organs is characteristic of Mark\'s healing accounts; it is not magic but the embodied encounter of divine healing-power with human impairment.</p>',
    "34": '<p><strong>ephphatha</strong> — Ephphatha — another Aramaic preservation (cf. 5:41); the word itself becomes performative: Jesus says be opened and the ears open. <em>Mogilalos</em> (v.32, speaking with difficulty or mute) is the LXX word in Isa 35:6 (the tongue of the mute will sing for joy) — Mark uses the Isaiah-term for the man healed, signaling that the Isaianic healing-sign is being enacted. The detail of Jesus\'s sighing (<em>estenaxen</em>) before the healing is a characteristic Markan note of Jesus\'s genuine human emotion and the weight he carries in the healing-mission.</p>',
    "35": '<p><strong>kai eutheōs diēnoichthēsan autou hai akoai, kai elythē ho desmos tēs glōssēs autou, kai elalei orthōs</strong> — and immediately his hearing was opened, and the bond of his tongue was loosed, and he spoke plainly — <em>eutheōs</em> again; the command was immediately effective. <em>diēnoichthēsan</em> (were opened — same verb-root as ephphatha). <em>desmos</em> (bond, restraint — what bound the tongue is now loosed) is released: <em>elythē</em> (was loosed, untied — aorist passive of <em>lyō</em>). <em>orthōs</em> (rightly, plainly, correctly — the adverb of straight/right) describes the quality of restored speech: not simply audible but properly formed.</p>',
    "36": '<p><strong>kai diestellato autois hina mēdeni legōsin</strong> — and he commanded them to tell no one — the Messianic Secret command (cf. 1:44; 5:43; 7:36); this is the seventh silence-command in Mark. <strong>Hoson de autois diestelleto, autoi mallon perissoteron ekērysson</strong> — but the more he commanded them the more abundantly they proclaimed it — the paradox intensifies: the command is categorical, the crowd\'s response is the inverse. <em>perissoteron</em> (more abundantly, excessively) — the more he prohibited, the more emphatically they proclaimed. The Messianic Secret cannot be contained by human command.</p>',
    "37": '<p><strong>kalōs panta pepoiēken, kai tous kōphous poiei akouein kai tous alalous lalein</strong> — he has done all things well, and the deaf he makes hear and the mute speak — <em>kalōs panta pepoiēken</em> (he has done all things well — perfect tense: the completed result stands) is widely recognized as an echo of Genesis 1:31 LXX: <em>kai eiden ho theos ta panta hosa epoiēsen, kai idou kala lian</em> (God saw everything he had made and behold it was very good). The crowd\'s acclamation of the healer uses the creation-completion formula, identifying Jesus\'s restoration-work as the new creation. The specific healings named — deaf hearing, mute speaking — are the Isaiah 35:5–6 messianic signs, completing the intertextual web from v.32.</p>'
  },
  "8": {
    "1": '<p><strong>Kai palin pollou ochlou ontos kai mē echontōn ti phagōsin</strong> — and again with a great crowd and they having nothing to eat — <em>palin</em> (again) links the second feeding explicitly to the first (6:35–44). The setting is implied Gentile territory east of Galilee (7:31 placed Jesus in the Decapolis). The pastoral crisis — large crowd, no food — is structurally identical to the first feeding, which will make the disciples\' confusion in v.4 more pointed.</p>',
    "2": '<p><strong>Splanchnizomai epi ton ochlon</strong> — I have compassion for the crowd — <em>splanchnizomai</em> (to be moved in the innards — the strongest Greek emotion-word; the word for gut-level compassion) is the same verb as in 6:34 (Jesus\'s compassion before the first feeding). The repetition is not accidental: both feedings are driven by the same inward motivation. The duration: three days (<em>treis hēmeras</em>) without food. The fast is already extended beyond the point of polite hunger into physical necessity.</p>',
    "3": '<p><strong>kai tines autōn apo makrothen hēkasin</strong> — and some of them have come from far away — <em>makrothen</em> (from a distance, from afar) appears in Ephesians 2:13,17 and Acts 2:39 for Gentiles who were "far off" but are drawn near in Christ. The word does not prove the crowd is Gentile but is consistent with the Decapolis location. The physical risk is genuine: they will be exhausted (<em>eklythēsontai en tē hodō</em> = will be undone on the road) without food on the journey home.</p>',
    "4": '<p><strong>kai apekrithēsan autō hoi mathētai autou hoti pothen touton dynēsetai tis hōde chortasai artōn</strong> — and his disciples answered him: from where will anyone be able to satisfy these with bread in this isolated place — the disciples\' question mirrors the first feeding question (6:37): the logistical impossibility is stated again despite the prior miracle. Mark presents the repetition without explanation; only in 8:17–21 will Jesus name the disciples\' failure to draw the inference as spiritual hardness. <em>erēmia</em> (isolated place, wilderness) is the word for the desert that echoes the Exodus feeding-tradition.</p>',
    "5": '<p><strong>hepta artous</strong> — seven loaves — versus five in the first feeding (6:38). The difference in numbers (and the different basket-counts that follow) supports reading the two feedings as distinct events rather than doublets: five and twelve are associated with Israel (five books of Moses; twelve tribes/apostles); seven and seven are associated with completeness/Gentile fullness (the Gentile nations). Mark preserves both accounts with the numerical differences intact.</p>',
    "6": '<p><strong>kai paraggellei tō ochlō anapesein epi tēs gēs</strong> — and he instructed the crowd to recline on the ground — the seating arrangement echoes the first feeding (6:39–40: the green grass, the groups). <strong>kai labōn tous hepta artous eucharistēsas eklasen kai edidou tois mathētais autou hina paratithōsin</strong> — and having taken the seven loaves, having given thanks, he broke them and gave to the disciples to set before the crowd — <em>eucharisteō</em> (to give thanks — the verb that becomes the technical term for the Eucharist in Paul\'s institution-account: 1 Cor 11:24; Luke 22:17,19). Mark uses both <em>eulogēō</em> (6:41, in the first feeding) and <em>eucharisteō</em> (8:6) across the two accounts; the Eucharistic vocabulary is in both, not only the second.</p>',
    "7": '<p><strong>kai eichon ichthydia oliga, kai eulogēsas auta eipen kai tauta paratithenai</strong> — and they had a few small fish, and having blessed them he said to set these before them also — the fish are handled separately with their own blessing (<em>eulogēsas</em>). The separation of bread and fish in the account maintains the two-element structure of both feeding accounts, consistent with the tradition being independently transmitted and not a scribal copy of the first account.</p>',
    "8": '<p><strong>kai ephagon kai echortasthēsan kai ēran perissemata klasmatōn hepta spyridas</strong> — and they ate and were satisfied, and they picked up seven baskets of broken pieces — <em>spyris</em> (large flexible basket — the type used to lower Paul over the Damascus wall: Acts 9:25) is different from <em>kophinos</em> (6:43; the standard Jewish basket, mentioned by Juvenal as the prop of Jewish street-vendors in Rome). The basket-type change between the two accounts, combined with the location in Gentile territory, supports reading the second feeding as directed toward a Gentile crowd — though Mark does not make this explicit.</p>',
    "9": '<p><strong>Ēsan de hōs tetrakischilioi</strong> — and they were about four thousand — the smaller number (4,000 vs. 5,000) is one of several numerical differences between the two feeding accounts that Jesus will recall precisely in vv.19–20 as evidence the disciples should have understood the significance. <em>kai apelysen autous</em> — and he dismissed them — the crowd is sent away; the mission moves on.</p>',
    "10": '<p><strong>kai euthys embas eis to ploion meta tōn mathētōn autou ēlthen eis ta merē Dalmanutha</strong> — and immediately getting into the boat with his disciples he came to the region of Dalmanutha — <em>Dalmanutha</em> is otherwise unattested in ancient sources; Matthew\'s parallel (15:39) reads Magadan/Magdala. The location is likely on the western shore of Galilee, Jewish territory, which explains the immediate Pharisaic encounter in v.11.</p>',
    "11": '<p><strong>kai exēlthon hoi Pharisaioi kai ērxanto syzētein autō, zētountes par\' autou sēmeion apo ouranou peirazōntes auton</strong> — and the Pharisees came out and began to argue with him, seeking from him a sign from heaven, testing him — <em>syzēteō</em> (to debate jointly, to argue against) indicates adversarial engagement, not honest inquiry. <em>sēmeion apo ouranou</em> (a sign from heaven) contrasts with the earthly healings already performed: they demand a cosmic confirmatory sign of a different order. <em>peirazō</em> (to test, to tempt) is the same word as Jesus\'s wilderness testing by Satan (1:13) — the Pharisees\' demand is framed as Satanic-scale opposition to Jesus\'s mission.</p>',
    "12": '<p><strong>kai anastenaxas tō pneumati autou legei, Ti hē genea hautē zētei sēmeion?</strong> — and sighing deeply in his spirit he says: why does this generation seek a sign? — <em>anastenaxas</em> (sighing deeply — intensified form of <em>stenazō</em> from 7:34, with <em>ana-</em> prefix adding depth) is located <em>tō pneumati autou</em> (in his spirit — the deep inner seat of the person), not merely a physical sigh. The sigh registers the profound spiritual failure the demand represents. <strong>amēn legō hymin, ei dothēsetai tē genea tautē sēmeion</strong> — the <em>amēn</em> oath-formula (<em>ei</em> + unfulfilled condition = "if a sign will be given... [it will not]") is an absolute refusal with the strongest possible assertive form. <em>genea</em> (generation, contemporaries) is used pejoratively throughout Mark\'s central section (8:38; 9:19).</p>',
    "13": '<p><strong>kai apheis autous palin embas apēlthen eis to peran</strong> — and leaving them again getting in he departed to the other side — the abrupt departure without further engagement characterizes Mark\'s ending of controversy scenes with the Pharisees: they receive no debate, no sign, no engagement — only the flat refusal of v.12 and Jesus\'s immediate departure. The crossing to the other side removes him from their vicinity without explanation or farewell.</p>',
    "14": '<p><strong>kai epelathonto labein artous, kai ei mē hena arton ouk eichon meth\' heautōn en tō ploiō</strong> — and they forgot to take bread, except they had one loaf with them in the boat — the disciples\' forgetfulness is the occasion for Jesus\'s teaching in vv.15–21. The <em>hena arton</em> (one loaf) in the boat is noted with precision; the disciples\' anxiety about it in v.16 is ironic given the two feedings immediately preceding. Some interpreters read the "one loaf" as a Christological symbol — the One Bread who is with them in the boat — but Mark does not make this explicit.</p>',
    "15": '<p><strong>horate, blepete apo tēs zymēs tōn Pharisaiōn kai tēs zymēs Hērōdou</strong> — watch out, beware of the leaven of the Pharisees and the leaven of Herod — <em>zymē</em> (leaven, yeast) as metaphor for pervasive invisible influence: a small amount leavens the whole batch (1 Cor 5:6; Gal 5:9). The pairing of Pharisees and Herod combines religious and political opposition: Pharisees are the religious establishment seeking a sign (v.11); Herod is the political authority who executed John (6:14–29) and who was troubled by reports about Jesus (6:16). The leaven-metaphor names their shared characteristic: a corrupting influence that spreads undetected.</p>',
    "16": '<p><strong>kai dielogizonto pros allēlous legontes hoti artous ouk echousin</strong> — and they reasoned with one another saying: it is because we have no bread — the disciples hear "leaven" (<em>zymē</em>) and immediately think bread (<em>artous</em>) — a misinterpretation on the level of Nicodemus hearing "born again" and thinking of physical birth (John 3:4). Their reasoning (<em>dielogizonto</em> — from <em>dialogizomai</em> = to reason through, same root as <em>dialogismos</em> in 2:6) is entirely literal; they have reduced a spiritual warning to a logistical concern about food supply.</p>',
    "17": '<p><strong>kai gnous legei autois, Ti dialogizesthe hoti artous ouk echete?</strong> — and knowing he says to them: why do you reason that you have no bread? — <em>gnous</em> (having perceived, having known — the immediate inward perception also used in 2:8 and 5:30) is Jesus\'s characteristic spiritual awareness of what is unspoken. <strong>oupō noeite oud\' syniete? pepōrōmenēn echete tēn kardian hymōn?</strong> — do you not yet perceive or understand? is your heart hardened? — <em>pepōrōmenēn</em> (hardened — perfect passive participle of <em>pōroō</em> = to harden, callous; <em>pōros</em> is a callus or calcification) is the Isaiah-language for spiritual insensibility (Isa 6:10; cf. Mark 3:5 where Jesus grieves the Pharisees\' hardened hearts). The disciples are diagnosed with the same condition as their opponents.</p>',
    "18": '<p><strong>ophtalmous echontes ou blepete kai ōta echontes ouk akouete? kai ou mnēmoneuete?</strong> — having eyes you do not see, and having ears you do not hear? and do you not remember? — the seeing-without-seeing and hearing-without-hearing are the prophetic diagnosis of covenant-hardened Israel (Jer 5:21; Ezek 12:2) now applied to the Twelve. The disciples have been given the mystery of the kingdom (4:11) but their perception remains blocked. The third question (<em>kai ou mnēmoneuete</em> = and do you not remember?) anticipates the recall of the two feedings in vv.19–20.</p>',
    "19": '<p><strong>hote tous pente artous eklasen eis tous pentakischilious, posous kophinous klasmatōn plēreis ērate?</strong> — when I broke the five loaves for the five thousand, how many baskets of fragments did you pick up? — the numerical recall is precise: five loaves, five thousand, twelve <em>kophinus</em>. The disciples answer correctly (<em>dōdeka</em>). The two feedings are not interchangeable events; the distinct numbers (five/twelve; seven/seven) are the evidence that should have generated theological inference about who was performing them.</p>',
    "20": '<p><strong>Hote tous hepta eis tous tetrakischilious, posōn spyridōn plērōmata klasmatōn ērate?</strong> — when the seven for the four thousand, how many baskets of fragments did you pick up? — the basket-word changes: <em>spyridas</em> (vs. <em>kophinous</em> in v.19) matching the actual accounts (6:43 kophinus; 8:8 spyridas). The disciples\' correct answers (<em>hepta</em> = seven) prove they remember the factual details; what they lack is the capacity to interpret them. The One who fed thousands twice is in the boat with them — bread-anxiety is incoherent.</p>',
    "21": '<p><strong>kai elegen autois, Oupō suniete?</strong> — and he said to them: do you not yet understand? — the pericope ends on an open question, not a declaration. <em>suniemi</em> (to understand, to put it together — the capacity to synthesize evidence into comprehension; used for the disciples\' failure throughout: 4:13; 6:52; 7:18) is the word for what the two feedings, correctly interpreted, should have produced. The question hangs: the answer is expected of the reader as much as the disciples.</p>',
    "22": '<p><strong>Kai erchontai eis Bēthsaida, kai pherosin autō tuphlon kai parakalosin auton hina autou hapsētai</strong> — and they came to Bethsaida, and they brought him a blind man and begged him to touch him — Bethsaida (on the northeastern shore of Galilee, Philip\'s tetrarchy) is outside Jewish Galilee. The healing-by-touch request (<em>hapsētai</em>) echoes the hemorrhaging woman\'s approach (5:27). The blind man is brought by others — the same pattern as the Syrophoenician daughter (7:25) and the deaf-mute (7:32).</p>',
    "23": '<p><strong>kai epilabomenos tēs cheiros tou typhlou exēnenken auton exō tēs kōmēs</strong> — and taking the blind man by the hand he led him outside the village — the withdrawal to privacy before healing (cf. 7:33 taking the deaf-mute apart from the crowd). Jesus leads the blind man by the hand — physical guidance as well as healing. <em>ptysas eis ta ommata autou</em> (having spat into his eyes) — spittle applied directly to the eyes, a physical healing medium consistent with 7:33. <strong>kai epitheis tas cheiras autō epērōta auton, Ei ti blepeis?</strong> — and having laid hands on him he asked him: do you see anything?</p>',
    "24": '<p><strong>kai anablepas elegen, Blepō tous anthrōpous hoti hōs dendra horō peripatountas</strong> — and looking up he said: I see the people, for as trees I see them walking — partial sight: the people are visible but unfocused, tree-sized and indistinct. This is the only Markan miracle requiring two applications; the first laying-on-hands produces incomplete healing. The structural positioning is significant: the two-stage healing follows the disciples\' two-stage understanding (they know who Jesus is — v.29 — but cannot yet grasp the cross), anticipating that full sight will require a second encounter with Christ\'s person and work.</p>',
    "25": '<p><strong>eita palin epethēken tas cheiras epi tous ophtalmous autou, kai dieblepen kai apekatestē kai eneblepsen tēlaugōs apanta</strong> — then again he laid hands on his eyes, and he looked intently and was restored and saw everything clearly — <em>apekatestē</em> (was restored completely — aorist passive of <em>apokathistēmi</em> = to reconstitute, restore fully; the same root as <em>apokatastasis</em>, the complete restoration of all things) and <em>tēlaugōs</em> (clearly, at a visible distance — the adverb of far-shining clarity) describe the completed state: full restoration of clear long-distance vision. The progression from no sight to partial sight to complete sight maps the spiritual journey that will continue through the next section of the Gospel.</p>',
    "26": '<p><strong>kai apesteilen auton eis oikon autou legōn, Mēde eis tēn kōmēn eiselthēs</strong> — and he sent him to his home saying: do not even enter the village — the Messianic Secret extended: not merely silence-commanded but direction-given (<em>eis oikon</em> = to your home). The healed man is sent back to domestic space, not into public space where news would spread. The restriction matches 5:19 (the Gerasene told to go to his house) and 7:29–30 (the Syrophoenician mother goes home to find her daughter healed).</p>',
    "27": '<p><strong>kai en tē hodō epērōta tous mathētas autou legōn autois, Tina me legousin hoi anthrōpoi einai?</strong> — and on the road he was asking his disciples saying to them: who do the people say that I am? — the Caesarea Philippi question is placed at Mark\'s structural midpoint: chapters 1–8 are the Galilean ministry of power; chapters 9–16 are the journey to the cross. The question on the road (<em>en tē hodō</em>) anticipates the journey-to-Jerusalem that will define the rest of the narrative. The popular identifications (v.28) all cast Jesus as a prophetic figure — John the Baptist, Elijah, one of the prophets — none identifies him as the Messiah.</p>',
    "28": '<p><strong>hoi de eipon autō legontes hoti Iōannēn ton Baptistēn, kai alloi Elian, alloi de hoti heis tōn prophētōn</strong> — they said: John the Baptist; others: Elijah; and others: one of the prophets — the three identifications map the prophetic horizon of expectation. The John the Baptist identification echoes Herod\'s fearful supposition (6:14,16). The Elijah identification connects to Malachi 4:5 (Elijah will return before the great Day of the Lord) — a widespread Second Temple expectation. The generic prophetic category casts Jesus in the tradition of the great OT spokespersons. None of these captures his identity; all project a known category onto him.</p>',
    "30": '<p><strong>kai epetimēsen autois hina mēdeni legōsin peri autou</strong> — and he charged them that they should tell no one about him — the Messianic Secret command follows the only correct identification. The command is now absolute and immediate: the correct confession (<em>su ei ho Christos</em>) triggers not proclamation but silence. The silence command makes the passion-prediction that immediately follows (v.31) the authorized context for understanding what kind of Messiah he is; without the cross, the confession is incomplete.</p>',
    "31": '<p><strong>kai ērxato didaskein autous hoti dei ton huion tou anthrōpou polla pathein kai apodokimasthēnai hypo tōn presbyterōn kai tōn archiereōn kai tōn grammateōn kai apoktanthēnai kai meta treis hēmeras anastēnai</strong> — and he began to teach them that it is necessary for the Son of Man to suffer many things and to be rejected by the elders and the chief priests and the scribes and to be killed and after three days to rise — <em>dei</em> (it is necessary, it is divinely obligatory — the word for divine necessity throughout Luke-Acts, John, and the NT passion-predictions) is the key term: the suffering is not accidental, permitted, or merely foreseen — it is divinely ordained. The three-part Sanhedrin (<em>presbyteroi</em> = elders; <em>archiereis</em> = chief priests; <em>grammateis</em> = scribes) is the complete Jerusalem authority that will execute the condemnation. <em>Meta treis hēmeras anastēnai</em> (to rise after three days) is stated as clearly as the rejection and death.</p>',
    "32": '<p><strong>kai parrēsia ton logon elalei</strong> — and plainly/openly he was speaking the word — <em>parrēsia</em> (frank speech, bold openness — the opposite of veiled or cryptic communication; the speech of one who holds back nothing). The passion-prediction is stated with maximum clarity to the disciples, contrasting with the parable-speech of chapter 4 which concealed from outsiders. <strong>kai proslabomenos ho Petros auton ērxato epitiman autō</strong> — and Peter taking him aside began to rebuke him — <em>epitimaō</em> (to rebuke, to charge sternly) is the word Jesus uses for rebuking demons (1:25; 3:12) and storms (4:39); Peter uses it against Jesus. The inversion is the narrative shock of the scene.</p>',
    "33": '<p><strong>ho de epistrapheis kai idōn tous mathētas autou epetimēsen Petrō kai legei, Hypage opisō mou, Satana, hoti ou phroneis ta tou theou alla ta tōn anthrōpōn</strong> — and turning and seeing his disciples he rebuked Peter and says: get behind me, Satan, because you do not think the things of God but the things of men — <em>phroneis</em> (you think/are minded — from <em>phroneō</em> = to set one\'s mind on, to be oriented toward; opposite of <em>tou theou phronein</em> that Paul calls the Spirit\'s mindset in Rom 8:5–6). <em>ta tou theou</em> vs. <em>ta tōn anthrōpōn</em> — the divine vs. human perspective on the Messiah is absolute: the divine plan includes the cross; the human perspective is repelled by it. The identification of Peter\'s protest with "Satan" (<em>Satana</em>) links this scene with 1:13 and 8:11 — resistance to the cross is Satanic at the structural level, regardless of the speaker\'s intent.</p>',
    "35": '<p><strong>hos gar ean thelē tēn psychēn autou sōsai apolesei autēn, hos d\' an apolese tēn psychēn autou heneken emou kai tou euangeliou sōsei autēn</strong> — for whoever wants to save his soul/life will lose it; but whoever loses his soul/life for my sake and the gospel will save it — <em>psychē</em> (soul/life — the single Greek word covering biological life and the eternal person; the polysemy is essential to the saying). The saying operates simultaneously on two levels: physical life (saved by denying Christ = ultimately lost; surrendered for Christ = ultimately saved) and eternal life (the same logic at a deeper level). The double-level meaning is irreducible; neither level cancels the other.</p>',
    "36": '<p><strong>ti gar ōphelei anthrōpon kerdēsai ton kosmon holon kai zēmiōthēnai tēn psychēn autou?</strong> — what does it profit a man to gain the whole world and to suffer loss in respect of his soul? — <em>kerdainō</em> (to gain profit — commercial vocabulary for profitable transactions) and <em>zēmioō</em> (to suffer loss, to be penalized — the corresponding loss-term; used in the papyri for fines) frame the calculation as a commercial exchange. The whole world on one side; the <em>psychē</em> on the other. The calculation is impossible: no sum of material acquisition compensates for the forfeiture of the person.</p>',
    "37": '<p><strong>ti gar dōsei anthrōpos antallagma tēs psychēs autou?</strong> — for what will a man give as an exchange for his soul? — <em>antallagma</em> (exchange, a compensating value — from <em>anti-allassō</em> = to exchange in place of) appears in Job 28:15 LXX where no gold or silver can be given as <em>antallagma</em> for wisdom. The rhetorical form is a second unanswerable question: there is no <em>antallagma</em>, no possible counterweight for the <em>psychē</em>. The soul\'s value exceeds any convertible equivalent. The commercial metaphor is completed: no bargain recovers what is lost when the soul is forfeited.</p>',
    "38": '<p><strong>hos gar ean epaischynthē me kai tous emous logous en tē genea tautē tē moichalidi kai hamartōlō, kai ho huios tou anthrōpou epaischynthēsetai auton</strong> — for whoever is ashamed of me and my words in this adulterous and sinful generation, the Son of Man will be ashamed of him — <em>epaischynō</em> (to be ashamed of, to feel the disgrace of association with — the verb of public dissociation in an honor-shame culture). In the first-century Mediterranean world, to be "ashamed of" someone is to publicly distance oneself from them to preserve one\'s own honor-standing. The Christological demand is stated as an inverse: if you deny the Messiah before humans to preserve social honor, the Son of Man will deny you at the judgment. <strong>hotan elthē en tē doxē tou patros autou meta tōn angelōn tōn hagiōn</strong> — when he comes in the glory of his Father with the holy angels — the coming-in-glory is the Daniel 7:13 enthronement event (cf. 13:26; 14:62); the holy angels attend the cosmic judgment scene (cf. Matt 25:31). The Son of Man who now walks to the cross will come in the Father\'s glory: the full reversal of the current hiddenness.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'mark')
    merge_comm(existing, MARK)
    save_comm('mkt-original', 'mark', existing)
    ch7 = len(existing.get('7', {}))
    ch8 = len(existing.get('8', {}))
    print(f'Mark 7–8 mkt-original written. Ch 7: {ch7} verses, Ch 8: {ch8} verses.')

if __name__ == '__main__':
    main()
